Here are comprehensive pytest-style unit tests for the `celsius_to_fahrenheit` function:

```python
import pytest
from celsius_to_fahrenheit import celsius_to_fahrenheit


class TestCelsiusToFahrenheitHappyPath:
    """Tests for typical, expected inputs."""

    def test_boiling_point_of_water(self):
        assert celsius_to_fahrenheit(100) == 212.0

    def test_freezing_point_of_water(self):
        assert celsius_to_fahrenheit(0) == 32.0

    def test_body_temperature(self):
        assert celsius_to_fahrenheit(37) == pytest.approx(98.6, rel=1e-3)

    def test_room_temperature(self):
        assert celsius_to_fahrenheit(20) == 68.0

    def test_positive_float(self):
        assert celsius_to_fahrenheit(22.5) == pytest.approx(72.5)


class TestCelsiusToFahrenheitEdgeCases:
    """Tests for boundary values and special cases."""

    def test_absolute_zero(self):
        assert celsius_to_fahrenheit(-273.15) == pytest.approx(-459.67, rel=1e-4)

    def test_negative_temperature(self):
        assert celsius_to_fahrenheit(-40) == -40.0  # -40 is equal in both scales

    def test_negative_float(self):
        assert celsius_to_fahrenheit(-10.5) == pytest.approx(13.1)

    def test_very_large_value(self):
        assert celsius_to_fahrenheit(1_000_000) == pytest.approx(1_800_032.0)

    def test_very_small_negative_value(self):
        assert celsius_to_fahrenheit(-1_000_000) == pytest.approx(-1_799_968.0)

    def test_fractional_temperature(self):
        assert celsius_to_fahrenheit(0.1) == pytest.approx(32.18, rel=1e-3)

    def test_returns_float(self):
        result = celsius_to_fahrenheit(0)
        assert isinstance(result, float)


class TestCelsiusToFahrenheitErrorCases:
    """Tests for invalid or unexpected inputs."""

    def test_string_input_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit("100")

    def test_none_input_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit(None)

    def test_list_input_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit([100])

    def test_dict_input_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit({"temp": 100})


class TestCelsiusToFahrenheitParametrized:
    """Parametrized tests for multiple known conversions."""

    @pytest.mark.parametrize("celsius, expected_fahrenheit", [
        (0,      32.0),
        (100,    212.0),
        (-40,    -40.0),
        (-273.15, -459.67),
        (37,     98.6),
        (20,     68.0),
        (-10,    14.0),
        (50,     122.0),
    ])
    def test_known_conversions(self, celsius, expected_fahrenheit):
        assert celsius_to_fahrenheit(celsius) == pytest.approx(expected_fahrenheit, rel=1e-4)
```

### Key decisions explained:

| Decision | Reason |
|---|---|
| `pytest.approx()` | Avoids floating-point precision issues for non-exact results |
| `-40` test | Unique crossover point where both scales are equal — great sanity check |
| Absolute zero test | Meaningful physical boundary |
| `isinstance(result, float)` | Verifies the return
